# Using pandas to build out the final .xlsx file precisely as requested
with pd.ExcelWriter(file_name, engine="openpyxl") as writer:
    for sheet_name, rows in data.items():
        df = pd.DataFrame(rows, columns=columns)
        
        # Write exactly formatted sheets without indexes
        df.to_excel(writer, sheet_name=sheet_name[:31], index=False)
        
        # Adjusting column widths for better Excel readability natively
        worksheet = writer.sheets[sheet_name[:31]]
        for idx, col in enumerate(df.columns):
            max_len = max(
                df[col].astype(str).map(len).max(),
                len(col)
            ) + 2
            col_letter = chr(65 + idx)
            worksheet.column_dimensions[col_letter].width = min(max_len, 40)

print(f"Data extraction successful! Look for `{file_name}` in the current directory.")